import{c as e,Q as s,j as t,m as n}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Buyer & User Personas","description":"Defining key target buyer and user profiles for the AI Workflow Orchestrator ecosystem","frontmatter":{"title":"Buyer & User Personas","description":"Defining key target buyer and user profiles for the AI Workflow Orchestrator ecosystem","keywords":"buyer persona, user persona, target audience, customer profiles","robots":"index, follow"},"headers":[],"relativePath":"en/personas/index.md","filePath":"en/personas/index.md","lastUpdated":null}'),i={name:"en/personas/index.md"};function o(r,a,l,p,c,u){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="👤-buyer-user-personas" tabindex="-1">👤 Buyer &amp; User Personas <a class="header-anchor" href="#👤-buyer-user-personas" aria-label="Permalink to &quot;👤 Buyer &amp; User Personas&quot;">​</a></h1><p>To guarantee that the <strong>AI Workflow Orchestrator</strong> solves real business and technical problems, we have mapped two primary personas: the <strong>Buyer</strong> (who makes acquisition decisions) and the <strong>User</strong> (the engineer operating the platform daily).</p><hr><h2 id="👔-1-buyer-persona-the-purchasing-decision-maker" tabindex="-1">👔 1. Buyer Persona: The Purchasing Decision Maker <a class="header-anchor" href="#👔-1-buyer-persona-the-purchasing-decision-maker" aria-label="Permalink to &quot;👔 1. Buyer Persona: The Purchasing Decision Maker&quot;">​</a></h2><ul><li><strong>Name:</strong> Marko Jovanovic</li><li><strong>Role:</strong> VP of Security &amp; Infrastructure</li><li><strong>Company:</strong> Fast-growing, mid-sized Fintech company</li><li><strong>Demographics:</strong> 42 years old, M.Sc. in Electrical Engineering, based in Belgrade.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  [ MARKO JOVANOVIC — VP OF SECURITY ]</span></span>
<span class="line"><span>   Goal: 100% compliance, absolute data security, controlled AI automation.</span></span>
<span class="line"><span>   Pain point: Legacy AI agents blindly executing shell tasks, risking data leaks.</span></span></code></pre></div><h3 id="goals-motivations" tabindex="-1">Goals &amp; Motivations: <a class="header-anchor" href="#goals-motivations" aria-label="Permalink to &quot;Goals &amp; Motivations:&quot;">​</a></h3><ul><li><strong>Compliance &amp; Auditing:</strong> Demands that every autonomous cloud transaction has a transparent, retroactively verifiable &quot;reasoning chain&quot; for PCI-DSS compliance audits.</li><li><strong>Risk Mitigation:</strong> Wants a platform that prevents any single AI agent from independently running execution commands without peer debate and strict verification.</li><li><strong>Cost Predictability:</strong> Requires strict token budget caps to avoid financial surprises from runaway AI loops.</li></ul><h3 id="key-pain-points" tabindex="-1">Key Pain Points: <a class="header-anchor" href="#key-pain-points" aria-label="Permalink to &quot;Key Pain Points:&quot;">​</a></h3><ul><li><strong>Data Leakage Fears:</strong> Distrusts traditional &quot;black-box&quot; agents that might submit sensitive corporate keys or schemas to public LLM endpoints.</li><li><strong>Insecure Configurations:</strong> Past negative experiences with AI code generation that created privileged GKE pods with exposed hostPorts.</li></ul><hr><h2 id="👩‍💻-2-user-persona-the-daily-operator" tabindex="-1">👩‍💻 2. User Persona: The Daily Operator <a class="header-anchor" href="#👩‍💻-2-user-persona-the-daily-operator" aria-label="Permalink to &quot;👩‍💻 2. User Persona: The Daily Operator&quot;">​</a></h2><ul><li><strong>Name:</strong> Jelena Nikolic</li><li><strong>Role:</strong> Lead DevOps &amp; Site Reliability Engineer (SRE)</li><li><strong>Company:</strong> Same fintech start-up</li><li><strong>Demographics:</strong> 29 years old, B.Sc. in Information Technology, based in Novi Sad.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                   [ JELENA NIKOLIC — LEAD SRE ]</span></span>
<span class="line"><span>   Goal: Fast orchestration, sandbox isolations, autonomous self-healing.</span></span>
<span class="line"><span>   Pain point: Wasting hours manually debugging minor configuration syntax issues.</span></span></code></pre></div><h3 id="goals-motivations-1" tabindex="-1">Goals &amp; Motivations: <a class="header-anchor" href="#goals-motivations-1" aria-label="Permalink to &quot;Goals &amp; Motivations:&quot;">​</a></h3><ul><li><strong>Rapid Automation:</strong> Wants to safely delegate complex infrastructure tasks (such as clustering databases) to an AI that designs and executes steps autonomously.</li><li><strong>Reduced Manual Overhead:</strong> Wants the AI system to diagnose and patch runtime errors dynamically (Self-Healing) without calling her for minor port overlaps.</li><li><strong>Seamless Integrations:</strong> Requires clean REST APIs and status SSE streams to easily integrate the orchestrator with current Slack alerts.</li></ul><h3 id="key-pain-points-1" tabindex="-1">Key Pain Points: <a class="header-anchor" href="#key-pain-points-1" aria-label="Permalink to &quot;Key Pain Points:&quot;">​</a></h3><ul><li><strong>Cascading Failures:</strong> Wasting significant operational time analyzing stdout/stderr when legacy AI scripts break mid-deployment.</li><li><strong>Opaque Debugging:</strong> Extreme difficulty tracing historical decisions and agent opinions that led to the current environment configuration.</li></ul>`,18)])])}const h=e(i,[["render",o]]);export{g as __pageData,h as default};
